select count(1) 
  from cotdl.tbl_piiordersteptable a
 where exists (select 1 
                 from cotdl.tbl_piiordersteptablewait b 
                where a.orderid = b.orderid and a.jobid = b.jobid and a.version = b.version and type='PRE' and a.stepid= b.stepid 
                  and a.db= b.db_w and a.owner= b.owner_w and a.table_name= b.table_name_w
                  and b.db= #{db, jdbcType=VARCHAR} and b.owner= #{owner, jdbcType=VARCHAR} and b.table_name= #{table_name, jdbcType=VARCHAR}
               )
   and a.status != 'Ended OK'
   and a.orderid = #{orderid} 
   and a.stepid = #{stepid, jdbcType=VARCHAR}
  order by orderid, jobid, version, stepseq, seq1 desc, seq2 desc, seq3 desc

		select orderid, status, forceokflag, to_char(basedate,'yyyy/mm/dd') as basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime, to_char(arcstart,'yyyy/mm/dd hh24:mi:ss') as arcstart, to_char(arcend,'yyyy/mm/dd hh24:mi:ss') as arcend, execnt, exetime, to_char(exestart,'yyyy/mm/dd hh24:mi:ss') as exestart, to_char(exeend,'yyyy/mm/dd hh24:mi:ss') as exeend,  sqlmsg
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} and db= #{db, jdbcType=VARCHAR} and owner= #{owner, jdbcType=VARCHAR} and table_name= #{table_name, jdbcType=VARCHAR}

		select orderid, status, forceokflag, to_char(basedate,'yyyy/mm/dd') as basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime, to_char(arcstart,'yyyy/mm/dd hh24:mi:ss') as arcstart, to_char(arcend,'yyyy/mm/dd hh24:mi:ss') as arcend, execnt, exetime, to_char(exestart,'yyyy/mm/dd hh24:mi:ss') as exestart, to_char(exeend,'yyyy/mm/dd hh24:mi:ss') as exeend,  sqlmsg
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and stepid= #{stepid, jdbcType=VARCHAR} and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

		select execnt
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and exetype= #{exetype, jdbcType=VARCHAR} and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

		select count(1)
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and exetype= #{exetype, jdbcType=VARCHAR} and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

		
		select count(1)
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
           and status = 'Ended not OK'
           and (seq1 < #{seq1} 
            	or (seq1 = #{seq1} and seq2 < #{seq2})
            	or (seq1 = #{seq1} and seq2 = #{seq2} and seq3 <  #{seq3})
            )

		
		select count(1)
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
           and status = 'Ended not OK'
           and (seq1 > #{seq1} 
              	or (seq1 = #{seq1} and seq2 > #{seq2})
            	or (seq1 = #{seq1} and seq2 = #{seq2} and seq3 >  #{seq3})
            )

