mapper.update:
update cotdl.tbl_piiordersteptable
   set 
		status= #{status, jdbcType=VARCHAR},
		exetime= (
			       TRUNC((sysdate-exestart)*24) || ':' || 
			       LPAD(TRUNC(mod((sysdate - exestart)*24,1)*60),2,'0' ) || ':' || 
			       LPAD(TRUNC(round(mod((sysdate - exestart)*24*60,1)*60)),2,'0' )
			       
				),
		exeend= SYSDATE,
		execnt= #{execnt, jdbcType=VARCHAR},
		sqlmsg= #{sqlmsg, jdbcType=VARCHAR}
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

update cotdl.tbl_piiordersteptable
   set 
		status= #{status, jdbcType=VARCHAR},
		exetime= (
			       TRUNC((sysdate-exestart)*24) || ':' || 
			       LPAD(TRUNC(mod((sysdate - exestart)*24,1)*60),2,'0' ) || ':' || 
			       LPAD(TRUNC(round(mod((sysdate - exestart)*24*60,1)*60)),2,'0' )
			       
				),
		exeend= SYSDATE,
		
		sqlmsg= #{sqlmsg, jdbcType=VARCHAR}
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} 
   and steptype in ('EXE_DELETE', 'EXE_UPDATE') 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

update cotdl.tbl_piiordersteptable
   set 
		execnt= #{execnt, jdbcType=VARCHAR}
where orderid= #{orderid} and stepid= #{stepid, jdbcType=VARCHAR} 
  and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

update cotdl.tbl_piiordersteptable
   set 
	   forceokflag= #{forceokflag, jdbcType=VARCHAR}
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR, jdbcType=VARCHAR} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

mapper.select:
 
		 
		select 
			orderid, status, forceokflag, basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime, arcstart, arcend, execnt, exetime, exestart, exeend, sqlmsg
		from ( 
				select 
					 ROWNUM rn, orderid, status, forceokflag, basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime, arcstart, arcend, execnt, exetime, exestart, exeend, sqlmsg
				from (
						 select orderid, status, forceokflag, to_char(basedate,'yyyy/mm/dd') as basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime, to_char(arcstart,'yyyy/mm/dd hh24:mi:ss') as arcstart, to_char(arcend,'yyyy/mm/dd hh24:mi:ss') as arcend, execnt, exetime, to_char(exestart,'yyyy/mm/dd hh24:mi:ss') as exestart, to_char(exeend,'yyyy/mm/dd hh24:mi:ss') as exeend, sqlmsg
					  	   from cotdl.tbl_piiordersteptable  
					  	  order by orderid, jobid, version, stepseq, seq1 desc, seq2 desc, seq3 desc
					 ) a
				 
		
	    
		
						
							and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and basedate = #{search2}
						
						
							and stepid = #{search3}
						
						
							and status = #{search4}
						
		
	    
	    
				
				order by orderid, jobid, version, stepseq, seq1 desc, seq2 desc, seq3 desc
			  ) k
		where rn <= #{pagenum} * #{amount} 
		  and rn > (#{pagenum} -1) * #{amount} 
		order by orderid, jobid, version, stepseq, seq1 desc, seq2 desc, seq3 desc
